--
-- Table structure for table `jadwal_rapat`
--

CREATE TABLE `jadwal_rapat` (
  `id` varchar(36) NOT NULL,
  `judul` varchar(255) NOT NULL,
  `deskripsi` text DEFAULT NULL,
  `tanggal` date NOT NULL,
  `jam_mulai` time NOT NULL,
  `jam_selesai` time NOT NULL,
  `tim` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL CHECK (json_valid(`tim`)),
  `peserta` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL CHECK (json_valid(`peserta`)),
  `repeat_type` enum('none','daily','weekly','custom') DEFAULT 'none',
  `repeat_days` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`repeat_days`)),
  `repeat_until` date DEFAULT NULL,
  `allow_stack` tinyint(1) DEFAULT 0,
  `open_offset_minutes` int(11) DEFAULT 0,
  `close_offset_minutes` int(11) DEFAULT 0,
  `lateness_threshold_minutes` int(11) DEFAULT 60,
  `jenis_kegiatan` varchar(50) DEFAULT 'rapat',
  `created_by` varchar(36) NOT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `created_at` datetime DEFAULT current_timestamp(),
  `peserta_mode` varchar(30) DEFAULT 'akun',
  `peserta_spesifik` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`peserta_spesifik`)),
  `jenis_kelpersahaan` varchar(50) DEFAULT 'rapat',
  `active_qr_id` varchar(36) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

